public class Q2 {
    public static void main(String[] args) {
        long totalRamGB = 32;

        // Q1: 75% of RAM for dedicated MySQL
        long bufferPoolGB = (long)(totalRamGB * 0.75); // 24GB

        // Q2: buffer pool (24GB) > working dataset (20GB) → near 100% hit rate
        long workingDatasetGB = 20;
        String hitRate = bufferPoolGB >= workingDatasetGB
            ? ">99% (entire working set fits in buffer pool)"
            : "~" + (100 * bufferPoolGB / workingDatasetGB) + "% (partial caching)";

        // Q3: monitor hit rate
        String command = "SHOW STATUS LIKE 'Innodb_buffer_pool_read%'";
        // Innodb_buffer_pool_reads = physical disk reads (misses)
        // Innodb_buffer_pool_read_requests = total logical reads
        // Hit rate = 1 - (reads / read_requests)

        // Q4: 1 instance per GB recommended (max 64)
        int instances = (int) Math.min(bufferPoolGB, 64); // 24

        System.out.println("Buffer pool: " + bufferPoolGB + "GB");
        System.out.println("Expected hit rate: " + hitRate);
        System.out.println("Monitor command: " + command);
        System.out.println("Instances: " + instances);
    }
}

