-- Deadlock-safe: always lock lower ID first
DELIMITER //
CREATE PROCEDURE transfer_safe(from_id BIGINT, to_id BIGINT, amount DECIMAL)
BEGIN
    START TRANSACTION;

    -- Lock BOTH rows in ascending ID order before any modification
    -- ORDER BY id ensures consistent lock acquisition across all callers
    SELECT id FROM accounts
    WHERE id IN (from_id, to_id)
    ORDER BY id
    FOR UPDATE;
    -- Now both rows are locked in id order — no cycle possible

    -- Validate sufficient balance
    IF (SELECT balance FROM accounts WHERE id = from_id) < amount THEN
        ROLLBACK;
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Insufficient balance';
    END IF;

    UPDATE accounts SET balance = balance - amount WHERE id = from_id;
    UPDATE accounts SET balance = balance + amount WHERE id = to_id;

    COMMIT;
END //
DELIMITER ;

-- Why this works:
-- Any concurrent call to transfer_safe for accounts (1,2) and (2,1)
-- will both try to lock id=1 first, then id=2
-- One gets the lock, other waits — no cycle, no deadlock
